fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    val visited = Array(m) { BooleanArray(n) { false } }
    var count = 0L

    for (i in 0 until m) {
        for (j in 0 until n) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                val queue = LinkedList<Pair<Int, Int>>()
                queue.add(Pair(i, j))
                visited[i][j] = true
                var sumIsland = grid[i][j]
                val directions = listOf(
                    Pair(-1, 0),
                    Pair(1, 0),
                    Pair(0, -1),
                    Pair(0, 1)
                )
                while (queue.isNotEmpty()) {
                    val (x, y) = queue.removeFirst()
                    for ((dx, dy) in directions) {
                        val nx = x + dx
                        val ny = y + dy
                        if (nx in 0 until m && ny in 0 until n) {
                            if (!visited[nx][ny] && grid[nx][ny] > 0L) {
                                visited[nx][ny] = true
                                sumIsland += grid[nx][ny]
                                queue.add(Pair(nx, ny))
                            }
                        }
                    }
                }
                if (sumIsland % k == 0L) {
                    count++
                }
            }
        }
    }
    return count
}
